import assert from 'assert';
import { ensureNoDisposablesAreLeakedInTestSuite } from '../../../../../base/test/common/utils.js';
import { createTextModel } from '../../../../test/common/testTextModel.js';
import { NamedRegionProvider } from '../../browser/namedRegionProvider.js';

suite('NamedRegionProvider', () => {
	ensureNoDisposablesAreLeakedInTestSuite();

	test('detects simple named regions with line comments', () => {
		const lines = [
			'// #region MySection',
			'function foo() {',
			'  console.log("hello");',
			'}',
			'// #endregion',
		];

		const model = createTextModel(lines.join('\n'));
		try {
			const provider = new NamedRegionProvider(model, { limit: 5000, update: () => { } });
			const regions = provider.detectNamedRegions();

			assert.strictEqual(regions.length, 1, 'should detect 1 region');
			assert.strictEqual(regions[0].name, 'MySection', 'region name should match');
			assert.strictEqual(regions[0].startLineNumber, 1, 'start line should be 1');
			assert.strictEqual(regions[0].endLineNumber, 5, 'end line should be 5');
		} finally {
			model.dispose();
		}
	});

	test('detects nested named regions', () => {
		const lines = [
			'// #region Outer',
			'  // #region Inner',
			'  function foo() {',
			'  }',
			'  // #endregion',
			'// #endregion',
		];

		const model = createTextModel(lines.join('\n'));
		try {
			const provider = new NamedRegionProvider(model, { limit: 5000, update: () => { } });
			const regions = provider.detectNamedRegions();

			assert.strictEqual(regions.length, 2, 'should detect 2 regions');
			assert.strictEqual(regions[0].name, 'Inner', 'first region name should be Inner');
			assert.strictEqual(regions[0].startLineNumber, 2, 'Inner region start should be 2');
			assert.strictEqual(regions[0].endLineNumber, 5, 'Inner region end should be 5');
			assert.strictEqual(regions[1].name, 'Outer', 'second region name should be Outer');
			assert.strictEqual(regions[1].startLineNumber, 1, 'Outer region start should be 1');
			assert.strictEqual(regions[1].endLineNumber, 6, 'Outer region end should be 6');
		} finally {
			model.dispose();
		}
	});

	test('detects named regions with block comments', () => {
		const lines = [
			'/* #region BlockSection */',
			'class MyClass {',
			'  constructor() {}',
			'}',
			'/* #endregion */',
		];

		const model = createTextModel(lines.join('\n'));
		try {
			const provider = new NamedRegionProvider(model, { limit: 5000, update: () => { } });
			const regions = provider.detectNamedRegions();

			assert.strictEqual(regions.length, 1, 'should detect 1 region');
			assert.strictEqual(regions[0].name, 'BlockSection', 'region name should match');
			assert.strictEqual(regions[0].startLineNumber, 1, 'start line should be 1');
			assert.strictEqual(regions[0].endLineNumber, 5, 'end line should be 5');
		} finally {
			model.dispose();
		}
	});

	test('handles regions with default name when name is omitted', () => {
		const lines = [
			'// #region',
			'function bar() {}',
			'// #endregion',
		];

		const model = createTextModel(lines.join('\n'));
		try {
			const provider = new NamedRegionProvider(model, { limit: 5000, update: () => { } });
			const regions = provider.detectNamedRegions();

			assert.strictEqual(regions.length, 1, 'should detect 1 region');
			assert.strictEqual(regions[0].name, 'Region', 'should use default name "Region"');
		} finally {
			model.dispose();
		}
	});

	test('handles unmatched endregion gracefully', () => {
		const lines = [
			'// #region Section1',
			'function foo() {}',
			'// #endregion',
			'// #endregion', // unmatched
		];

		const model = createTextModel(lines.join('\n'));
		try {
			const provider = new NamedRegionProvider(model, { limit: 5000, update: () => { } });
			const regions = provider.detectNamedRegions();

			assert.strictEqual(regions.length, 1, 'should detect 1 region (unmatched endregion ignored)');
			assert.strictEqual(regions[0].name, 'Section1', 'region name should match');
		} finally {
			model.dispose();
		}
	});

	test('detects multiple separate regions', () => {
		const lines = [
			'// #region FirstRegion',
			'function first() {}',
			'// #endregion',
			'',
			'// #region SecondRegion',
			'function second() {}',
			'// #endregion',
		];

		const model = createTextModel(lines.join('\n'));
		try {
			const provider = new NamedRegionProvider(model, { limit: 5000, update: () => { } });
			const regions = provider.detectNamedRegions();

			assert.strictEqual(regions.length, 2, 'should detect 2 regions');
			assert.strictEqual(regions[0].name, 'FirstRegion', 'first region name');
			assert.strictEqual(regions[0].startLineNumber, 1, 'first region start');
			assert.strictEqual(regions[0].endLineNumber, 3, 'first region end');
			assert.strictEqual(regions[1].name, 'SecondRegion', 'second region name');
			assert.strictEqual(regions[1].startLineNumber, 5, 'second region start');
			assert.strictEqual(regions[1].endLineNumber, 7, 'second region end');
		} finally {
			model.dispose();
		}
	});

	test('computes folding regions with named regions', () => {
		const lines = [
			'// #region MySection',
			'function foo() {',
			'  console.log("hello");',
			'}',
			'// #endregion',
		];

		const model = createTextModel(lines.join('\n'));
		try {
			const provider = new NamedRegionProvider(model, { limit: 5000, update: () => { } });
			provider.compute(require('../../../../base/common/cancellation.js').CancellationToken.None).then(foldingRegions => {
				if (foldingRegions) {
					assert.strictEqual(foldingRegions.length, 1, 'should have 1 folding region');
					assert.strictEqual(foldingRegions.getStartLineNumber(0), 1, 'region start should be 1');
					assert.strictEqual(foldingRegions.getEndLineNumber(0), 5, 'region end should be 5');
					assert.strictEqual(foldingRegions.getType(0), 'MySection', 'region type should be the name');
				}
			});
		} finally {
			model.dispose();
		}
	});

	test('handles empty file', () => {
		const model = createTextModel('');
		try {
			const provider = new NamedRegionProvider(model, { limit: 5000, update: () => { } });
			const regions = provider.detectNamedRegions();

			assert.strictEqual(regions.length, 0, 'should detect no regions in empty file');
		} finally {
			model.dispose();
		}
	});

	test('handles regions with whitespace in names', () => {
		const lines = [
			'// #region My Complex Section Name',
			'function foo() {}',
			'// #endregion',
		];

		const model = createTextModel(lines.join('\n'));
		try {
			const provider = new NamedRegionProvider(model, { limit: 5000, update: () => { } });
			const regions = provider.detectNamedRegions();

			assert.strictEqual(regions.length, 1, 'should detect 1 region');
			assert.strictEqual(regions[0].name, 'My Complex Section Name', 'region name should preserve spaces');
		} finally {
			model.dispose();
		}
	});

	test('handles indented region markers', () => {
		const lines = [
			'class MyClass {',
			'  // #region Methods',
			'  method1() {}',
			'  method2() {}',
			'  // #endregion',
			'}',
		];

		const model = createTextModel(lines.join('\n'));
		try {
			const provider = new NamedRegionProvider(model, { limit: 5000, update: () => { } });
			const regions = provider.detectNamedRegions();

			assert.strictEqual(regions.length, 1, 'should detect 1 region');
			assert.strictEqual(regions[0].name, 'Methods', 'region name should match');
			assert.strictEqual(regions[0].startLineNumber, 2, 'start line should be 2');
			assert.strictEqual(regions[0].endLineNumber, 5, 'end line should be 5');
		} finally {
			model.dispose();
		}
	});
});

